async function loadUser(req, res, next) {
  const { id } = req.params;
  if (!id) return next(new Error('missing_id'));

  try {
    const user = await db.findUser(id);
    if (!user) return next(new Error('not_found'));

    await audit.log(user);
    await cache.set(id, user);

    return res.json(user);
  } catch (err) {
    return next(err);
  }
}
